#include <stdio.h>
#include <stdint.h>

// TCP Header Structure (20 bytes minimum)
struct tcphdr {
    uint16_t source_port;      // Source port (16 bits)
    uint16_t dest_port;        // Destination port (16 bits)
    uint32_t seq_num;          // Sequence number (32 bits)
    uint32_t ack_num;          // Acknowledgment number (32 bits)
    uint8_t  data_offset;      // Data offset (4 bits) + reserved (4 bits)
    uint8_t  flags;            // Control flags (URG, ACK, PSH, RST, SYN, FIN)
    uint16_t window;          // Window size (16 bits)
    uint16_t checksum;         // Header and data checksum (16 bits)
    uint16_t urgent_ptr;      // Urgent pointer (16 bits)
    // Options may follow if data_offset > 5
};

// IP Header Structure (Network Layer)
struct iphdr {
    uint8_t  version_ihl;     // Version (4 bits) + IHL (4 bits)
    uint8_t  tos;             // Type of service
    uint16_t total_length;   // Total packet length
    uint16_t identification;  // Identification for fragmentation
    uint16_t flags_offset;   // Flags (3 bits) + Fragment offset (13 bits)
    uint8_t  ttl;            // Time to live
    uint8_t  protocol;       // Protocol (TCP=6, UDP=17, ICMP=1)
    uint16_t checksum;       // Header checksum
    uint32_t source_ip;      // Source IP address
    uint32_t dest_ip;        // Destination IP address
};

// Ethernet Frame Header (Data Link Layer)
struct ethhdr {
    uint8_t  dest_mac[6];     // Destination MAC address
    uint8_t  source_mac[6];   // Source MAC address
    uint16_t ether_type;     // EtherType (0x0800 for IPv4)
};

int main() {
    printf("TCP/IP Encapsulation Example\n");
    printf("================================\n");
    printf("Application Layer: User Data\n");
    printf("Transport Layer: Segment (TCP Header + Data) = %lu bytes\n", sizeof(struct tcphdr));
    printf("Network Layer: Packet (IP Header + Segment) = %lu bytes\n", sizeof(struct iphdr) + sizeof(struct tcphdr));
    printf("Data Link Layer: Frame (Ethernet Header + Packet + CRC)\n");
    printf("Physical Layer: Converted to bits and transmitted\n");
    return 0;
}
